import{_ as e,o as t,c as n,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Compaction","description":"","frontmatter":{"summary":"Context window + compaction: how OpenSoul keeps sessions under model limits","read_when":["You want to understand auto-compaction and /compact","You are debugging long sessions hitting context limits"],"title":"Compaction"},"headers":[],"relativePath":"concepts/compaction.md","filePath":"concepts/compaction.md","lastUpdated":null}'),a={name:"concepts/compaction.md"};function i(c,o,r,p,d,l){return t(),n("div",null,[...o[0]||(o[0]=[s('<h1 id="context-window-compaction" tabindex="-1"><a class="header-anchor" href="#context-window-compaction">#</a> Context Window &amp; Compaction</h1><p>Every model has a <strong>context window</strong> (max tokens it can see). Long-running chats accumulate messages and tool results; once the window is tight, OpenSoul <strong>compacts</strong> older history to stay within limits.</p><h2 id="what-compaction-is" tabindex="-1"><a class="header-anchor" href="#what-compaction-is">#</a> What compaction is</h2><p>Compaction <strong>summarizes older conversation</strong> into a compact summary entry and keeps recent messages intact. The summary is stored in the session history, so future requests use:</p><ul><li>The compaction summary</li><li>Recent messages after the compaction point</li></ul><p>Compaction <strong>persists</strong> in the session’s JSONL history.</p><h2 id="configuration" tabindex="-1"><a class="header-anchor" href="#configuration">#</a> Configuration</h2><p>See <a href="/docs/concepts/compaction">Compaction config &amp; modes</a> for the <code>agents.defaults.compaction</code> settings.</p><h2 id="auto-compaction-default-on" tabindex="-1"><a class="header-anchor" href="#auto-compaction-default-on">#</a> Auto-compaction (default on)</h2><p>When a session nears or exceeds the model’s context window, OpenSoul triggers auto-compaction and may retry the original request using the compacted context.</p><p>You’ll see:</p><ul><li><code>🧹 Auto-compaction complete</code> in verbose mode</li><li><code>/status</code> showing <code>🧹 Compactions: &lt;count&gt;</code></li></ul><p>Before compaction, OpenSoul can run a <strong>silent memory flush</strong> turn to store durable notes to disk. See <a href="/docs/concepts/memory">Memory</a> for details and config.</p><h2 id="manual-compaction" tabindex="-1"><a class="header-anchor" href="#manual-compaction">#</a> Manual compaction</h2><p>Use <code>/compact</code> (optionally with instructions) to force a compaction pass:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact Focus on decisions and open questions</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="context-window-source" tabindex="-1"><a class="header-anchor" href="#context-window-source">#</a> Context window source</h2><p>Context window is model-specific. OpenSoul uses the model definition from the configured provider catalog to determine limits.</p><h2 id="compaction-vs-pruning" tabindex="-1"><a class="header-anchor" href="#compaction-vs-pruning">#</a> Compaction vs pruning</h2><ul><li><strong>Compaction</strong>: summarises and <strong>persists</strong> in JSONL.</li><li><strong>Session pruning</strong>: trims old <strong>tool results</strong> only, <strong>in-memory</strong>, per request.</li></ul><p>See <a href="/docs/concepts/session-pruning">/concepts/session-pruning</a> for pruning details.</p><h2 id="tips" tabindex="-1"><a class="header-anchor" href="#tips">#</a> Tips</h2><ul><li>Use <code>/compact</code> when sessions feel stale or context is bloated.</li><li>Large tool outputs are already truncated; pruning can further reduce tool-result buildup.</li><li>If you need a fresh slate, <code>/new</code> or <code>/reset</code> starts a new session id.</li></ul>',23)])])}const h=e(a,[["render",i]]);export{u as __pageData,h as default};
